#include <bits/stdc++.h>
using namespace std;
int n,a[105],maxx=INT_MIN,ans;
int main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=0;i<n;i++){
		cin>>a[i];
		maxx=max(a[i],maxx);
	}
	for(int i=0;i<n;i++){
		if(a[i]!=maxx){
			ans+=a[i];
		}
	}
	cout<<ans;
	return 0;
}
